VALUES ('AK-MED-MAL-STANDARD-OF-CARE', 5, 'AK Medical Malpractice: Standard of Care (AS 09.55.540)', 'content_check', 'personal_injury', 'medical_malpractice', 'complaint', 'state', 'AK',
    jsonb_build_object('sub_specialization_type', 'medical_malpractice', 'authority_level', 'contextual_rule', 'statute', 'AS 09.55.540', 'standard_text', 'Provider must exercise the degree of care, skill, and treatment that a reasonably competent provider in the same field would use under same or similar circumstances', 'key_elements', jsonb_build_array('Duty: provider-patient relationship established', 'Breach: failure to meet standard of care', 'Causation: breach proximately caused injury', 'Damages: measurable harm resulted'), 'national_standard', 'Alaska generally applies a national/statewide standard of care rather than a strict locality rule', 'res_ipsa', 'Available where negligence is obvious without expert testimony (e.g., surgical instrument left in body)', 'informed_consent', 'Separate claim: provider must disclose risks a reasonably prudent patient would find material to treatment decision', 'voluntary_arbitration', 'Parties may agree to arbitrate medical malpractice disputes (AS 09.55.535); not mandatory', 'verification', jsonb_build_object('statute_verified', true, 'sources', jsonb_build_array('AS 09.55.540', 'Alaska Statutes Title 9 Ch. 55', 'Justia — Alaska Medical Malpractice'), 'confidence', 'high')),
